head.script:
//==================================================================================================================
// id       : fs_103_01_03b 
// 이름     : 세금계산서접수등록(부서별)
// 경로     : 물류/정산/세금계산서/
// 작 성 자 : 조성빈
// 작 업 일 : 2025-12-22
// 사용계정 : 내부
// 비고     : 
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//            
//==================================================================================================================
scwin.vCurDate;
scwin.vQryStDt;
scwin.vQryEndDt;
scwin.clnt_chk;
scwin.pay_cond;
scwin.sum;
scwin.suspensePaySum;
scwin.selectRow;

scwin.onpageload = async function() {
    scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
	scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
	scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth($c.date.getServerDateTime( scwin.vCurDate.substring(0,6)));  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
    scwin.clnt_chk = "T";
	scwin.pay_cond = "T";
	scwin.sum = 0; //가지급금 금액 산정용
	scwin.suspensePaySum = 0;

    const codeOptions = [
        { grpCd : "SD070", compID : "acb_taxnClsCd,gr_certiList:taxnClsCd" },
        { grpCd : "FM018", compID : "acb_reqPayMthdCd"}, 
    ];
    await $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":100});
};

scwin.setCommonCodeCallBack = function () {

    const codeOptions1 = [ 
        {
            method: "getLuxeComboData", 
            param1: "LogisticsPurchaseEvidenceEBC", 
            param2: "retriveSelpchItemCdList",
            param3: ["CMP"],
            compID: "acb_pchsItemCd" ,
            requestIdleCallback : "scwin.test"
        }
    ];
    $c.data.setGauceUtil(codeOptions1, scwin.comboSetCallBack);
};

scwin.comboSetCallBack = function(){
    $c.data.dataListFilter(dlt_commonCodeFM018, "fltrCd2 == '10' || fltrCd2 == '20'");

    acb_pchsItemCd.addItem("전체", "", "", 0);
    acb_pchsItemCd.setMaxLength(50);
    acb_pchsItemCd.setSelectedIndex(0); // 매입항목

    acb_taxnClsCd.addItem("선택", "", "", 0);
    acb_taxnClsCd.setSelectedIndex(0);

    acb_reqPayMthdCd.addItem("선택", "", "", 0);
    acb_reqPayMthdCd.setSelectedIndex(0);

    scwin.f_SetDefaultData();

    // ed_bfPayDt.style.visibility = "hidden";

    // $p.setTimeout(function() {
    //     ed_pchsDeptCd.setValue("1G5");
    //     ica_pchsIntendDtSt.setValue("20071130");
    //     ica_pchsIntendDtEnd.setValue("20071130");
    //     acb_recptYn.setValue("N");
    //     ed_pchsDeptCd.focus();
    //     ed_pchsDeptCd.blur();
    // }, {"delay":150});

};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {

    ica_pchsIntendDtSt.setValue(scwin.vQryStDt);  // 매입예정일자시작
    ica_pchsIntendDtEnd.setValue(scwin.vQryEndDt);  // 매입예정일자종료
    acb_recptYn.setMaxLength(4);
    acb_recptYn.setSelectedIndex(0); // 접수구분
    // document.all.div_id.style.visibility = "hidden";

    ds_provHeader.insertRow();
    // Session 이용
    ds_provHeader.setCellData(0, "reqAcctDeptCd", $c.data.getMemInfo("acctDeptCd"));
    // 로그인사번,부서
    ds_provHeader.setCellData(0, "drawEmpNo", $c.data.getMemInfo("empNo"));
    ds_provHeader.setCellData(0, "drawAcctDeptCd", $c.data.getMemInfo("acctDeptCd"));
};


//-------------------------------------------------------------------------
// 거래명세서 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCertiList = async function () {
    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    var rs = await $c.gus.cfValidate([ica_pchsIntendDtSt, ica_pchsIntendDtEnd, ed_pchsDeptCd]);
    if (!rs) {
        return;
    }
    rs = await $c.gus.cfIsAfterDate(ica_pchsIntendDtSt.getValue(), ica_pchsIntendDtEnd.getValue())
    if (!rs) {
        await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ica_pchsIntendDtSt.focus();
        return;
    }
    $c.sbm.execute(sbm_searchCertiList);
} ;

//-------------------------------------------------------------------------
// 상세 조회
//-------------------------------------------------------------------------
scwin.f_RetrievePurchaseEvidence = async function (row) {
    // 팝업화면에게 key 정보인 전표번호를 넘겨준다.
    let win_url = "/ui/ds/fs/adjm/fs_103_01_01p.xml";
    let data = {
        "slipNo"     : ds_certiList.getCellData(row, "slipNo")
    };
    let opts = {
        id : "detailPop"
        , popupName : "세금계산서 접수 등록 상세"
        , modal : true
        , type : "browserPopup"
        , width : 840
        , height : 670
        , title : "세금계산서 접수 등록 상세"
    };
    await $c.win.openPopup(win_url, opts, data);
};

//-------------------------------------------------------------------------
// 매입증빙(상호, 사업자번호) 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveClntInfo = async function (row) {
    // ds_purchaseCerti.ClearData();
    ds_purchaseCerti.set("adjmDept", "");
    ds_purchaseCerti.set("slipDt", "");
    ds_purchaseCerti.set("evidKndClsCd", "");
    ds_purchaseCerti.set("taxnClsCd", "");
    ds_purchaseCerti.set("summary", "");
    ds_purchaseCerti.set("drawEmpNo", "");
    ds_purchaseCerti.set("drawAcctDeptCd", "");
    ds_purchaseCerti.set("pchsClntNo", "");
    ds_purchaseCerti.set("busiNo", "");
    ds_purchaseCerti.set("spplyDt", "");
    ds_purchaseCerti.set("spplyAmt", "");
    ds_purchaseCerti.set("vat", "");
    ds_purchaseCerti.set("elecAuthTrgtYn", "");
    ds_purchaseCerti.set("crcCd", "");
    // ds_clntInfo.ClearData();
    ds_clntInfo.removeAll();

    ds_purchaseCerti.set("pchsClntNo", ds_certiList.getCellData(row, "pchsClntNo"));
    ds_purchaseCerti.set("adjmDept", ds_certiList.getCellData(row, "pchsDeptCd"));     
    ds_purchaseCerti.set("crcCd", ds_certiList.getCellData(row, "crcCd"));

    await $c.sbm.execute(sbm_searchClntInfo);
    if (ds_clntInfo.getRowCount() > 0) {
        ds_certiList.setCellData(row, "busiNm", ds_clntInfo.getCellData(0, "nmCmpy"));  // 상호
        ds_certiList.setCellData(row, "busiNo", ds_clntInfo.getCellData(0, "busiNo"));  // 사업자번호
        ds_certiList.setCellData(row, "elecAuthTrgtYn", ds_clntInfo.getCellData(0, "elecAuthTrgtYn"));	//역발행 거래처 여부

        scwin.pay_cond = "T";

        if(scwin.clnt_chk == "T"){        
            ds_payInfo.set("interDataYn", 0); 
            if( ds_certiList.getCellData(row, "pchsDeptCd")=="1G20"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="1G32"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="1G33"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="1G31"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="1G34"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="1G35"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="1G36"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="6A5"||
                ds_certiList.getCellData(row, "pchsDeptCd")=="4A9"){ // 재무팀 노규헌 대리 요청으로 인천복운 추가(2018.10)

                if(ds_clntInfo.getCellData(0, "inatPayYn")=="1"){
                    //당월
                    if(ds_clntInfo.getCellData(0, "payCycCd")=="3"){
                        var strDate = ds_certiList.getCellData(row, "pchsIntendDt"); 
                        var year = strDate.substr(0,4);				
                        var month = strDate.substr(4,2);
                        var day = strDate.substr(6,2);
                        var date = new Date(year, month-1, day);

                        var yyyy = date.getFullYear().toString();
                        var mm = "";

                        if(mm==0){
                            mm = (date.getMonth()+1).toString();
                        } else {
                            mm = (date.getMonth()).toString();
                        } 

                        if(mm < 10){
                            mm = "0"+mm;				
                        }	 

                        var dd = ds_clntInfo.getCellData(0, "payDd");	

                        if(dd=="30"){
                            dd = ( new Date( yyyy, mm, 0) ).getDate();	
                        }	

                        var strPayDate = yyyy + mm + dd;	
                        ds_holiday.set("stdDt", strPayDate);
                        await $c.sbm.execute(sbm_holiday);

                        ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                        ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 
                        ds_certiList.setCellData(row, "reqPayMthdCd", ds_clntInfo.getCellData(0, "payCntShtCd"));

                        if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                            gr_certiList.setColumnReadOnly('payDt', false);
                        } else {	 
                            gr_certiList.setColumnReadOnly('payDt', true);
                        } 				           	
                        ds_payInfo.set("interDataYn", 1); 
                        scwin.pay_cond = "T";
                        //익월
                    } else if(ds_clntInfo.getCellData(0, "payCycCd")=="1"){

                        var strDate = ds_certiList.getCellData(row, "pchsIntendDt"); 
                        var year = strDate.substr(0,4);				
                        var month = strDate.substr(4,2);
                        var day = strDate.substr(6,2);
                        var date = new Date(year, month-1, day);
                        var yyyy = date.getFullYear().toString();
                        var mm = "";

                        if(mm==0){
                            mm = (date.getMonth()+2).toString();
                        } else {
                            mm = (date.getMonth()+1).toString();
                        } 

                        if(mm < 10){
                            mm = "0"+mm;				
                        } else if(mm > 12){
                            mm = (Number(mm)-12).toString();
                            yyyy = (Number(yyyy)+1).toString();							   
                            if(mm < 10){
                                mm = "0"+mm;	
                            }
                        }			

                        var dd = ds_clntInfo.getCellData(0, "payDd");	

                        if(dd=="30"){
                            dd = ( new Date( yyyy, mm, 0) ).getDate();	
                        }					
                        var strPayDate = yyyy + mm + dd;

                        ds_holiday.set("stdDt", strPayDate);

                        await $c.sbm.execute(sbm_holiday);									  

                        ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                        ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 

                        if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                            gr_certiList.setColumnReadOnly('payDt', false);			           		        	
                        } else {	 
                            gr_certiList.setColumnReadOnly('payDt', true);  
                        } 				           	
                        ds_payInfo.set("interDataYn", 1); 
                        scwin.pay_cond = "T";
                        //익익월
                    } else if(ds_clntInfo.getCellData(0, "payCycCd")=="2"){

                        var strDate = ds_certiList.getCellData(row, "pchsIntendDt");
                        var year = strDate.substr(0,4);				
                        var month = strDate.substr(4,2);

                        var day = strDate.substr(6,2);
                        var date = new Date(year, month-1, day);

                        var yyyy = date.getFullYear().toString();
                        var mm = "";

                        if(mm==0){
                            mm = (date.getMonth()+3).toString();
                        } else {
                            mm = (date.getMonth()+2).toString();
                        } 						

                        if(mm < 10){
                            mm = "0"+mm;				
                        } else if(mm > 12){
                            mm = (Number(mm)-12).toString();
                            yyyy = (Number(yyyy)+1).toString();							   
                            if(mm < 10){
                                mm = "0"+mm;	
                            }
                        }				

                        var dd = ds_clntInfo.getCellData(0, "payDd");
                        if(dd=="30"){
                            dd = ( new Date( yyyy, mm, 0) ).getDate();	
                        }	

                        var strPayDate = yyyy + mm + dd;
                        ds_holiday.set("stdDt", strPayDate);
                        await $c.sbm.execute(sbm_holiday);									  

                        ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                        ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 
                        ds_certiList.setCellData(row, "reqPayMthdCd", ds_clntInfo.getCellData(0, "payCntShtCd"));

                        if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                            gr_certiList.setColumnReadOnly('payDt', false);			           		        	
                        } else {	 
                            gr_certiList.setColumnReadOnly('payDt', true);	 
                        } 				           	
                        ds_payInfo.set("interDataYn", 1);
                        scwin.pay_cond = "T"; 
                        //익익익월
                    }else if(ds_clntInfo.getCellData(0, "payCycCd")=="4"){

                        var strDate = ds_certiList.getCellData(row, "pchsIntendDt");
                        var year = strDate.substr(0,4);				
                        var month = strDate.substr(4,2);

                        var day = strDate.substr(6,2);
                        var date = new Date(year, month-1, day);

                        var yyyy = date.getFullYear().toString();
                        var mm = "";

                        if(mm==0){
                            mm = (date.getMonth()+4).toString();
                        } else {
                            mm = (date.getMonth()+3).toString();
                        } 	

                        if(mm < 10){
                            mm = "0"+mm;				
                        } else if(mm > 12){
                            mm = (Number(mm)-12).toString();
                            yyyy = (Number(yyyy)+1).toString();							   
                            if(mm < 10){
                                mm = "0"+mm;	
                            }
                        }			

                        var dd = ds_clntInfo.getCellData(0, "payDd");
                        if(dd=="30"){
                            dd = ( new Date( yyyy, mm, 0) ).getDate();	
                        }	
                        var strPayDate = yyyy + mm + dd;

                        ds_holiday.set("stdDt", strPayDate);
                        await $c.sbm.execute(sbm_holiday);									  

                        ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                        ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 
                        ds_certiList.setCellData(row, "reqPayMthdCd", ds_clntInfo.getCellData(0, "payCntShtCd"));

                        if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                            gr_certiList.setColumnReadOnly('payDt', false);			           		        	
                        } else {	 
                            gr_certiList.setColumnReadOnly('payDt', true);	 
                        } 				           	

                        ds_payInfo.set("interDataYn", 1);
                        scwin.pay_cond = "T";  
                    //익익익익월          	   
                    } else if(ds_clntInfo.getCellData(0, "payCycCd")=="5"){

                        var strDate = ds_certiList.getCellData(row, "pchsIntendDt");
                        var year = strDate.substr(0,4);				
                        var month = strDate.substr(4,2);

                        var day = strDate.substr(6,2);
                        var date = new Date(year, month-1, day);

                        var yyyy = date.getFullYear().toString();
                        var mm = "";

                        if(mm==0){
                            mm = (date.getMonth()+5).toString();
                        } else {
                            mm = (date.getMonth()+4).toString();
                        } 	

                        if(mm < 10){
                            mm = "0"+mm;				
                        } else if(mm > 12){
                            mm = (Number(mm)-12).toString();
                            yyyy = (Number(yyyy)+1).toString();							   
                            if(mm < 10){
                                mm = "0"+mm;	
                            }
                        }			

                        var dd = ds_clntInfo.getCellData(0, "payDd");
                        if(dd=="30"){
                            dd = ( new Date( yyyy, mm, 0) ).getDate();	
                        }	
                        var strPayDate = yyyy + mm + dd;

                        ds_holiday.set("stdDt", strPayDate);
                        await $c.sbm.execute(sbm_holiday);									  

                        ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                        ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 
                        ds_certiList.setCellData(row, "reqPayMthdCd", ds_clntInfo.getCellData(0, "payCntShtCd")); 

                        if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                            gr_certiList.setColumnReadOnly('payDt', false);			           		        	
                        } else {	 
                            gr_certiList.setColumnReadOnly('payDt', true);	
                        } 				           	
                        ds_payInfo.set("interDataYn", 1);
                        scwin.pay_cond = "T";

                    } else if(ds_clntInfo.getCellData(0, "payCycCd")=="6"){
                        if(ds_certiList.getCellData(row, "etd") != ""){
                            var strDate = ds_certiList.getCellData(row, "etd"); 
                            var year = strDate.substr(0,4);				
                            var month = strDate.substr(4,2)-1;
                            var day = strDate.substr(6,2);
                            var date = new Date(year, month, day);
                            var payDate = new Date(Date.parse(date) 
                                + ds_clntInfo.getCellData(0, "payDd") * 1000 * 60 * 60 * 24);  //after 5days

                            var yyyy = payDate.getFullYear().toString();
                            var mm = (payDate.getMonth() + 1).toString();

                            if(mm < 10){
                                mm = "0"+mm;				
                            }				

                            var dd = payDate.getDate().toString();
                            if(dd < 10){
                                dd = "0"+dd;				
                            }
                            var strPayDate = yyyy + mm + dd;

                            ds_holiday.set("stdDt", strPayDate); 
                            await $c.sbm.execute(sbm_holiday);									  

                            ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                            ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 
                            ds_certiList.setCellData(row, "reqPayMthdCd", ds_clntInfo.getCellData(0, "payCntShtCd"));

                            //ed_payDt.setValue()strPayDate;  
                            //ed_bfPayDt.setValue()strPayDate;  


                            if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                                gr_certiList.setColumnReadOnly('payDt', false);				           		        	
                            } else {	 
                                gr_certiList.setColumnReadOnly('payDt', true);	
                            } 					           	
                            ds_payInfo.set("interDataYn", 1); 
                            scwin.pay_cond = "T";

                        } 
                    } else if(ds_clntInfo.getCellData(0, "payCycCd")=="7"){

                        if(ds_certiList.getCellData(row, "eta") != ""){
                            var strDate = ds_certiList.getCellData(row, "eta");  
                            var year = strDate.substr(0,4);				
                            var month = strDate.substr(4,2)-1;
                            var day = strDate.substr(6,2);
                            var date = new Date(year, month, day);
                            var payDate = new Date(Date.parse(date) 
                                + ds_clntInfo.getCellData(0, "payDd") * 1000 * 60 * 60 * 24);  //after 5days
                            var yyyy = payDate.getFullYear().toString();
                            var mm = (payDate.getMonth() + 1).toString();

                            if(mm < 10){
                                mm = "0"+mm;				
                            }	

                            var dd = payDate.getDate().toString();

                            if(dd < 10){
                                dd = "0"+dd;				
                            }
                            var strPayDate = yyyy + mm + dd;

                            ds_holiday.set("stdDt", strPayDate);
                            await $c.sbm.execute(sbm_holiday);									  

                            ds_certiList.setCellData(row, "payDt", ds_nextdate.get("nextDt"));  
                            ds_certiList.setCellData(row, "bfPayDt", ds_nextdate.get("nextDt")); 
                            ds_certiList.setCellData(row, "reqPayMthdCd", ds_clntInfo.getCellData(0, "payCntShtCd"));

                            //ed_payDt.setValue()strPayDate; 
                            //ed_bfPayDt.setValue()strPayDate;  

                            if(ds_clntInfo.getCellData(0, "payDtChgYn")=="Y"){
                                gr_certiList.setColumnReadOnly('payDt', false);	 			           		        	
                            } else {	 
                                gr_certiList.setColumnReadOnly('payDt', true);	 
                            } 	

                            ds_payInfo.set("interDataYn", 1); 
                            scwin.pay_cond = "T";	
                        }     	           
                    }else{	
                        ds_certiList.setCellData(row, "payDt", "");  
                        ds_certiList.setCellData(row, "bfPayDt", ""); 
                        ds_certiList.setCellData(row, "reqPayMthdCd", "");

                    }

                    var clntNo = ds_certiList.getCellData(row, "pchsClntNo")  

                    if(clntNo=="249544"){			            				            
                        acb_reqPayMthdCd.setValue("40");
                    } 
                }            
            }            
            //근무구분
            // ds_imntClnt.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=IL061&cd="+ds_certiList.getCellData(row, "pchsClntNo") ;
            // ds_imntClnt.Reset(); 
            ds_imntClnt.set('grpCd', 'IL061');
            ds_imntClnt.set('cd', ds_certiList.getCellData(row, "pchsClntNo"));
            var rs = await $c.sbm.execute(sbm_imntClnt);
        } else {
            scwin.clnt_chk = "T";             
        }           
    }       

}

//-------------------------------------------------------------------------
