//-------------------------------------------------------------------------
// 세금계산서 접수 저장
//-------------------------------------------------------------------------
scwin.f_RegistPurchaseEvidence = async function () {   
    // 미접수(전표번호 미생성)인 경우만 가능
    var slipNo = "";
    var cnt = 0;
    for (var i=0; i<ds_certiList.getRowCount(); i++) {      
        slipNo = ds_certiList.getCellData(i, "slipNo");
        if (ds_certiList.getCellData(i, "chk") == "T") {
            if (slipNo != "") { 
                await $c.gus.cfAlertMsg("이미 접수된 건이 포함되어 있습니다.");
                return;
            }
            cnt++;
        }
    }  

    // Data 변경 여부 조회
    if (cnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }
    var rs = await scwin.f_checkCertiBeforeSave();
    //위수탁 업체 체크로직 추가 2009 01 20     
    if (rs == false){
        return false;
    }

    // 선택건의 공급가액, 부가세 합계 계산
    for (var i=0; i<ds_certiList.getRowCount(); i++) {    
        var spplyAmt = 0;
        var vat = 0;
        var suspensePay = "0";

        if (ds_certiList.getCellData(i, "chk") == "T") {
            spplyAmt += ds_certiList.getCellData(i, "spplyAmt");
            vat += ds_certiList.getCellData(i, "vat");
            suspensePay += ds_certiList.getCellData(i, "suspensePay");

            // 정산부서, 전표일자, 증빙구분, 적요, 작성자, 작성귀속부서, 공급일자 체크
            if (ds_certiList.getCellData(i,"adjmDept")==""|| ds_certiList.getCellData(i,"slipDt")==""   || ds_certiList.getCellData(i,"taxnClsCd")==""     || 
                ds_certiList.getCellData(i,"summary")=="" || ds_certiList.getCellData(i,"drawEmpNo")==""|| ds_certiList.getCellData(i,"drawAcctDeptCd")==""||
                ds_certiList.getCellData(i,"spplyDt")=="") {

                    await $c.win.alert((i+1)+"행의 필수값이 입력되지 않았습니다.");
                    return;
            }

            if(ds_certiList.getCellData(i,"payDt") !=""){
                if(ds_certiList.getCellData(i,"reqPayMthdCd") == ""){
                    await $c.win.alert((i+1)+"행 ,지급일을 입력하면 지급 방법도 입력해야 합니다.");
                    return;
                }
            }

            if(ds_certiList.getCellData(i,"reqPayMthdCd") !=""){
                if(ds_certiList.getCellData(i,"payDt") == ""){
                    await $c.win.alert((i+1)+"행 ,지급방법을 입력하면 지급일도 입력해야 합니다.");
                    return;
                }
            }

            // 마이너스 금액은 전표생성할  수 없습니다.
            if (spplyAmt < 0) { 
                await $c.gus.cfAlertMsg((i+1)+"행 ,마이너스 금액은 전표생성할  수 없습니다.");
                return;
            }

            // 부가세 금액이 ZERO이면 증빙구분을 세금계산서로 선택할 수 없습니다.  2008.07.07
            if (vat == 0) { 
                if (ds_certiList.getCellData(i,"evidKndClsCd") == "10" || ds_certiList.getCellData(i,"evidKndClsCd") == "11"){
                    await $c.gus.cfAlertMsg("부가세 금액이 ZERO이면 증빙구분을 세금계산서로 선택할 수 없습니다.");
                    return;
                }
            }else if(vat != 0){
                if (ds_certiList.getCellData(i,"evidKndClsCd") == "20"){
                    await $c.gus.cfAlertMsg("부가세 금액이 ZERO가아니면 증빙구분을 영세율세금계산서로 선택할 수 없습니다.");
                    return;
                }
            }

            //가지급금 검사로직 추가 2016 09 13 서동원
            if(ds_certiList.getCellData(i,"suspensePay") != '0' && ds_prov.getCellData(0, "setlDt") == null ){
                await $c.win.alert("가지급금이 있습니다.\n가지급금을 처리하시고 접수하십시오.");
                scwin.f_Prepay();
                return;
            }   
        }
    }
    var rs = await $c.win.confirm(MSG_CM_CRM_001);
    if (rs) {  // 저장하시겠습니까?
        $c.sbm.execute(sbm_saveRegistPurchaseEvidence);
    }
};

