    /*위수탁업체일 경우 체크로직 20090120
        1. 체크된 row
        2. 계약시작일자 가 null이 아닐경우 == OP128과 zz514에 데이터가 있을 경우  
    */
    for (var i=0; i<ds_certiList.getRowCount(); i++) {      
        if (ds_certiList.getCellData(i, "chk") == "T") {
            //1. 계약일자와 전표일자 체크  
            if( ds_certiList.getCellData(i, "ctrtStDt") != "" && ds_certiList.getCellData(i, "ctrtEndDt") != ""  ){ 
                if(!( ds_certiList.getCellData(i, "slipDt") >= ds_certiList.getCellData(i, "ctrtStDt") && ds_certiList.getCellData(i, "slipDt") <= ds_certiList.getCellData(i, "ctrtEndDt") ) ){
                    if( (ds_certiList.getCellData(i, "pchsClntClsCd") == '11' || ds_certiList.getCellData(i, "pchsClntClsCd") == '16' || ds_certiList.getCellData(i, "pchsClntClsCd") == '17') ){
                        await $c.win.alert("거래명세서번호 : "+ds_certiList.getCellData(i, "certiNo")+" 는 전표일자  : "+ ds_certiList.getCellData(i, "slipDt")+" 로, 거래처 : "+ed_pchsClntNo.getValue()
                            +" 의 차량적용기간 "+ds_certiList.getCellData(i, "ctrtStDt")+" ~ "+ds_certiList.getCellData(i, "ctrtEndDt")+"에서 벗어났습니다. "  );
                        return false;
                        break;
                    }                           
                }

                if((ds_certiList.getCellData(i, "slipDt")  >= ds_certiList.getCellData(i, "ctrtStDt") && ds_certiList.getCellData(i, "slipDt")  <= ds_certiList.getCellData(i, "ctrtEndDt"))){
                    if(!(ds_certiList.getCellData(i, "pchsClntClsCd") == '11' || ds_certiList.getCellData(i, "pchsClntClsCd") == '16' || ds_certiList.getCellData(i, "pchsClntClsCd") == '17') ){
                        await $c.win.alert("거래명세서번호 : "+ds_certiList.getCellData(i, "certiNo")+" 는 전표일자  : "+ds_certiList.getCellData(i, "slipDt") +" 로, 거래처 : "+ ds_certiList.getCellData(i, "pchsClntNo")
                            +" 의 차량적용기간 "+ds_certiList.getCellData(i, "ctrtStDt")+" ~ "+ds_certiList.getCellData(i, "ctrtEndDt")+"에서 벗어났습니다. " );
                        return false;
                        break;
                    }                           
                }
            } 

            if(!(ds_certiList.getCellData(i, "ctrtStDt") != "" && ds_certiList.getCellData(i, "ctrtEndDt") != "")  ){  
                if((ds_certiList.getCellData(i, "pchsClntClsCd") == '11' || ds_certiList.getCellData(i, "pchsClntClsCd") == '16' || ds_certiList.getCellData(i, "pchsClntClsCd") == '17')){
                    await $c.win.alert("계약번호가 없습니다. 거래처의 매입거래처 종류는 "+ds_certiList.getCellData(i, "pchsClntClsNm") +" 로 위수탁이나 직영차이면 안됩니다. 거래처 관리에서 매입거래처 구분코드를 확인하십시오. ");
                    return false;
                    break;
                }                   
            }
        }
    } 
};

//-------------------------------------------------------------------------
// 매입증빙별거래명세서, 매입확정/매입증빙 정보 Data Clear
//-------------------------------------------------------------------------
scwin.f_PchsDataClear = async function () {
    for (var i=0; i<ds_certiList.getRowCount(); i++) {      
        if(ds_certiList.getCellData(i, "slipNo") == "") {

            // 전표일자, 공급일자 구하기 위한 변수
            var inputDate = ica_pchsIntendDtEnd.getValue() ; 
            var year      = inputDate.substring(0,4);
            var month     = inputDate.substring(4,6);

            ds_certiList.setCellData(i, "adjmDept", "");  // 정산부서코드
            ed_nmCmpy.setValue("");  // 상호
            ed_busiNo.setValue("");  // 사업자번호

            ds_certiList.setCellData(i, "slipDt", year + month + $c.date.getLastDateOfMonth(year + scwin.f_del_zero(month)));  // 전표일자
            ds_certiList.setCellData(i, "evidKndClsCd", "10");  // 증빙구분(세금계산서)
            ds_certiList.setCellData(i, "taxnClsCd", "01");  // 과세구분(과세)
            ds_certiList.setCellData(i, "summary", "");  // 적요
            ds_certiList.setCellData(i, "drawEmpNo", $c.data.getMemInfo("empNo"));  // 작성자코드
            ds_certiList.setCellData(i, "drawEmpNm", $c.data.getMemInfo("userNm"));  // 작성자명
            ds_certiList.setCellData(i, "drawAcctDeptCd", $c.data.getMemInfo("acctDeptCd"));  // 작성귀속부서코드
            ds_certiList.setCellData(i, "drawAcctDeptNm", $c.data.getMemInfo("acctDeptNm"));  // 작성귀속부서명
            ds_certiList.setCellData(i, "spplyDt", year + month + $c.date.getLastDateOfMonth(year + scwin.f_del_zero(month)));  // 공급일자
            ds_certiList.setCellData(i, "adjmDept", ds_certiList.getCellData(i, "pchsDeptCd"));

            await scwin.f_chkOpenCommonPopUp(ds_certiList.getCellData(i, "adjmDept"), "", 4);

            await scwin.f_RetrieveClntInfo(i);  // 매입증빙(상호,사업자번호) 조회

            if(ds_certiList.getCellData(i, "vat")==0){
                ds_certiList.setCellData(i, "evidKndClsCd", "20");
                ds_certiList.setCellData(i, "taxnClsCd", "02");
            }else{
                ds_certiList.setCellData(i, "evidKndClsCd", "10");
                ds_certiList.setCellData(i, "taxnClsCd", "01");
            }

            ds_certiList.setCellData(i, "summary", ds_certiList.getCellData(i, "rmk"));            //적요
            ds_certiList.setCellData(i, "spplyDt", ds_certiList.getCellData(i, "pchsIntendDt")); //공급일자
        }
    }
};

scwin.f_del_zero = function ( Name ) {
    var  x, ch;
    var  i=0;
    var  newVal="";

    for(x = 0; x < Name.length ; x++){
        ch= Name.substring(x,x+1);
        if( ch != "0") {
            newVal = Name.substring(x);
            break;
        }
    }    
    return  newVal;
};

