};



scwin.gr_certiList_onviewchange = async function (info) {
    // OnColumnChanged(row,colid)
    var colid = info.colId;
    var row = info.rowIndex;

    if(colid == "evidKndClsCd"){
		if (ds_certiList.getCellData(row, "evidKndClsCd") == "10") {  // 증빙구분(세금계산서)
	    	ds_certiList.setCellData(row, "taxnClsCd", "01");  // 과세구분(과세)
	    	ds_certiList.setCellData(row, "elecAuthTrgtYn", 0);  // 전자세금계산서(미적용)
	    	gr_certiList.setCellReadOnly(row, 'elecAuthTrgtYn', true);    

	    } else if (ds_certiList.getCellData(row, "evidKndClsCd") == "00") {  // 증빙구분(기타-부가세없음)
	        ds_certiList.setCellData(row, "taxnClsCd", "02");  // 과세구분(과세)
	    	ds_certiList.setCellData(row, "elecAuthTrgtYn", 0);  // 전자세금계산서(미적용)
	        gr_certiList.setCellReadOnly(row, "taxnClsCd", true);    
	        gr_certiList.setCellReadOnly(row, "elecAuthTrgtYn", true);    
	    } else {
	        ds_certiList.setCellData(row, "taxnClsCd", "");  // 과세구분(과세)
	    	ds_certiList.setCellData(row, "elecAuthTrgtYn", 0);  // 전자세금계산서(미적용)
	        gr_certiList.setCellReadOnly(row,"taxnClsCd", false);    
	        gr_certiList.setCellReadOnly(row,"elecAuthTrgtYn", true);    
	    }  
	}

	if (colid == "chk" && ds_certiList.getCellData(row, "slipNo") == "") {
		if(ds_certiList.getCellData(row, "chk") == "T"){
			await scwin.f_RetrieveClntInfo2(row, ds_certiList.getCellData(row, "pchsClntNo"));
		}
	}

	// 전표일자 입력시 공급일자 동시 입력
	if(colid == "slipDt") {
		ds_certiList.setCellData(row, "spplyDt", ds_certiList.getCellData(row, "slipDt"));  // 과세구분(과세)
	}

	// 정산부서
	if(colid == "adjmDept") {
		await scwin.f_chkOpenCommonPopUp(ds_certiList.getCellData(row, "adjmDept"),"", 4);
	}

	// 작성자
	if(colid == "drawEmpNo") {
		await scwin.f_chkOpenCommonPopUp(ds_certiList.getCellData(row, "drawEmpNo"),"", 5);
	}

	// 작성부서
	if(colid == "drawAcctDeptCd") {
		await scwin.f_chkOpenCommonPopUp(ds_certiList.getCellData(row, "drawAcctDeptCd"),"", 6);
	}
};

scwin.gr_certiList_onrowindexchange = async function (row, oldRow) {
    // OnRowPosChanged(row)
    if (ds_certiList.getCellData(row, "chk") == "T" && ds_certiList.getCellData(row, "slipNo") != "") {
		await $c.win.alert("전표생성된 건은 선택할 수 없습니다.");
		ds_certiList.setCellData(row, "chk", "F");
		return;
	}
};

scwin.excelDown = async function () {
    var count = ds_certiList.getRowCount();
    if (!(count > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
        return;
    } else {
        // gr_certiList.SetExcelTitle(1, "value:세금계산서 접수 등록;"  // 표시할 타이틀
        //                             + "font-face:'돋움체';" // 폰트
        //                             + "font-size:12pt;"    // 폰트 크기
        //                             + "font-color:black;"  // 폰트 색깔
        //                             + "bgcolor:#ffffff;"   // 배경 색깔
        //                             + "align:center;"      // 정렬
        //                             + "line-color:white;"  // 타이틀 부분 테두리선 색깔
        //                             + "line-width:0pt;"    // 타이틀 테두리선 굵기
        //                             + "skiprow:1;");       // 타이틀 다음 떼는 로우 수

        // // cfGridToExcel(그리드ID, "엑셀 파일의 쉬트명", "엑셀 파일명", 저장 옵션);
        // cfGridToExcel(gr_certiList, "세금계산서 접수 등록", "세금계산서 접수 등록.xls", 4 + 8 + 16);

        var argGridTotalCol = 0;
        for (var i = 0 ; i < gr_certiList.getTotalCol(); i++) {
            if (gr_certiList.getColumnVisible(i)) {
                argGridTotalCol++;
            }
        }

        const infoArr = [{
            rowIndex    : 0
            , colIndex    : 0
            , rowSpan     : 1
            , colSpan     : argGridTotalCol
            , text        : "세금계산서 접수 등록"
            , textAlign   : "center"
            // , fontSize    : "12"
            , fontName    : "돋움체"
            , color       : "black"
            , fontWeight  : ""
            , drawBorder  : "false"
            , borderColor : ""
            , borderWidth : ""
            , wordWrap    : "true"
            , bgColor     : "#ffffff"
        }];
        const options = {
            fileName : "세금계산서 접수 등록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: "세금계산서 접수 등록",
            type : "1",
            startRowIndex: 2,
            // removeColumns: "0,21",
            // hiddenVisible : true,
            // useSubTotal :"true", 
            // useSubTotalData  : "true",
            // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
            // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
        };
        $c.data.downloadGridViewExcel(gr_certiList, options, infoArr);
    } 
};

